+fn archive_agent_slug_for_exclusion(agent: &str) -> String {
+    match agent.trim().to_ascii_lowercase().as_str() {
+        "claude" | "claude-code" | "claude_code" => "claude_code".to_string(),
+        other => other.to_string(),
+    }
+}
