+    /// Rebuild token_daily_stats from the token_usage ledger.
+    pub fn rebuild_token_daily_stats(&self) -> Result<usize> {
+        const CONVERSATION_BATCH_SIZE: usize = 1_000;
+        const TOKEN_USAGE_BATCH_SIZE: usize = 10_000;
+
